def merge_within(pairs, d):
    if not pairs:
        return []

    merged = []
    for start, end in sorted(pairs):
        if merged and start - d <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])

    return merged
